#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n,b=0;    cin >> n;    vi arr(n);//sorted_arr(n);    for (int i = 0; i < n; i++) {        cin >> arr[i];    }    //sort(sorted_arr.begin(), sorted_arr.end());    int mini=INT_MAX;        for (int i = 1; i < n; i++) {                if (arr[i]-arr[i-1]>=0){            b=(arr[i]-arr[i-1])/2+1;            mini=min(mini,b);            }        else{            mini=0;        }                    }    cout << mini << "\n";          } // --- MAIN DRIVER ---int main(){    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}